import React, { useState, useEffect } from 'react';
import { purchasesAPI, suppliersAPI, productsAPI, supplierProductsAPI } from '../services/api';
import toast from 'react-hot-toast';
import {
  Plus,
  FileText,
  X,
  DollarSign,
  TrendingDown
} from 'lucide-react';

const Purchases = () => {
  const [purchases, setPurchases] = useState([]);
  const [suppliers, setSuppliers] = useState([]);
  const [products, setProducts] = useState([]);
  const [loading, setLoading] = useState(true);
  const [showModal, setShowModal] = useState(false);
  const [formData, setFormData] = useState({
    proveedor: '',
    type: 'contado',
    paymentMethod: 'efectivo',
    user: 'default_user',
    items: [],
    notes: '',
    invoice: ''
  });
  const [currentItem, setCurrentItem] = useState({
    product: '',
    quantity: 1,
    unitCost: 0
  });
  const [discountInfo, setDiscountInfo] = useState(null);

  useEffect(() => {
    fetchData();
    fetchSuppliers();
    fetchProducts();
  }, []);

  const fetchData = async () => {
    try {
      const purchasesRes = await purchasesAPI.getAll();
      setPurchases(purchasesRes.data.data);
    } catch (error) {
      toast.error('Error al cargar datos');
    } finally {
      setLoading(false);
    }
  };

  const fetchSuppliers = async () => {
    try {
      const suppliersRes = await suppliersAPI.getAll();
      setSuppliers(suppliersRes.data.data);
    } catch (error) {
      console.error('Error al cargar proveedores:', error);
    }
  };

  const fetchProducts = async () => {
    try {
      const productsRes = await productsAPI.getAll();
      setProducts(productsRes.data.data);
    } catch (error) {
      console.error('Error al cargar productos:', error);
    }
  };

  const handleAddItem = async () => {
    if (!currentItem.product || currentItem.quantity <= 0 || currentItem.unitCost <= 0) {
      toast.error('Completa todos los campos del item');
      return;
    }

    const newItem = { ...currentItem };
    setFormData({
      ...formData,
      items: [...formData.items, newItem]
    });
    setCurrentItem({ product: '', quantity: 1, unitCost: 0 });
    setDiscountInfo(null);
  };

  const handleRemoveItem = (index) => {
    setFormData({
      ...formData,
      items: formData.items.filter((_, i) => i !== index)
    });
  };

  const handleProductChange = async (productId) => {
    const product = products.find(p => p._id === productId);
    setCurrentItem({
      ...currentItem,
      product: productId,
      unitCost: product?.cost || 0
    });

    // Buscar condiciones de descuento si hay proveedor seleccionado
    if (formData.proveedor && productId) {
      try {
        const supplierProductsRes = await supplierProductsAPI.getAll({
          supplier: formData.proveedor,
          product: productId,
          active: true
        });

        if (supplierProductsRes.data.data.length > 0) {
          const supplierProduct = supplierProductsRes.data.data[0];
          setDiscountInfo({
            discountPercentage: supplierProduct.discountPercentage,
            discountDays: supplierProduct.discountDays,
            baseCost: supplierProduct.baseCost
          });

          // Actualizar el costo unitario con el costo base del proveedor
          setCurrentItem({
            ...currentItem,
            product: productId,
            unitCost: supplierProduct.baseCost
          });
        } else {
          setDiscountInfo(null);
        }
      } catch (error) {
        console.error('Error al buscar descuentos:', error);
        setDiscountInfo(null);
      }
    }
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      if (formData.items.length === 0) {
        toast.error('Agrega al menos un item');
        return;
      }

      await purchasesAPI.create(formData);
      toast.success('Compra creada correctamente');
      setShowModal(false);
      setFormData({
        proveedor: '',
        type: 'contado',
        paymentMethod: 'efectivo',
        user: 'default_user',
        items: [],
        notes: '',
        invoice: ''
      });
      fetchData();
    } catch (error) {
      console.error('Error al crear compra:', error);
      toast.error('Error al crear compra');
    }
  };

  const formatCurrency = (amount) => {
    return new Intl.NumberFormat('es-MX', {
      style: 'currency',
      currency: 'MXN'
    }).format(amount);
  };

  const calculateSavings = () => {
    if (!discountInfo || !currentItem.unitCost) return 0;
    const baseTotal = currentItem.unitCost * currentItem.quantity;
    return baseTotal * (discountInfo.discountPercentage / 100);
  };

  if (loading) {
    return (
      <div className="flex items-center justify-center h-64">
        <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-primary-600"></div>
      </div>
    );
  }

  return (
    <div className="space-y-6">
      {/* Header */}
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-2xl font-semibold text-gray-900">Compras</h1>
          <p className="mt-1 text-sm text-gray-600">
            Gestiona las compras a proveedores
          </p>
        </div>
        <button className="btn btn-primary btn-md">
          <Plus className="h-4 w-4 mr-2" />
          Nueva Compra
        </button>
      </div>

      {/* Purchases Table */}
      <div className="card">
        <div className="overflow-x-auto">
          <table className="table">
            <thead>
              <tr>
                <th>Fecha</th>
                <th>Proveedor</th>
                <th>Productos</th>
                <th>Total</th>
                <th>Tipo</th>
                <th>Estado</th>
                <th>Acciones</th>
              </tr>
            </thead>
            <tbody>
              {purchases.map((purchase) => (
                <tr key={purchase._id}>
                  <td>
                    {new Date(purchase.date).toLocaleDateString('es-MX')}
                  </td>
                  <td>{purchase.proveedor?.name}</td>
                  <td>
                    <div className="space-y-1">
                      {purchase.items?.map((item, index) => (
                        <div key={index} className="text-sm">
                          {item.quantity}x {item.product?.name}
                        </div>
                      ))}
                    </div>
                  </td>
                  <td className="text-right font-medium">
                    {formatCurrency(purchase.total)}
                  </td>
                  <td>
                    <span className="capitalize">{purchase.type}</span>
                  </td>
                  <td>
                    <span className={`badge badge-${
                      purchase.status === 'pagada' ? 'success' :
                      purchase.status === 'pendiente' ? 'warning' : 'danger'
                    }`}>
                      {purchase.status}
                    </span>
                  </td>
                  <td>
                    <button className="text-primary-600 hover:text-primary-900">
                      <FileText className="h-4 w-4" />
                    </button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

export default Purchases;
